#include <bits/stdc++.h>
using namespace std;
int s,a;
bool zs(int x) {
	if(x<=1) {
		return 0;
	}
	for(int i=2; i*i<=x; i++) {
		if(x%i==0) {
			return 0;
		}
	}
	return 1;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>s;
	for(int i=2; i<s; i++) {
		if(zs(i)&&zs(s-i)){
			a=max(a,i*(s-i));
		}
	}
	cout<<a;
	return 0;
}
